SELECT p.id AS id, p.order_id AS orderId, o.order_no AS orderNo, p.member_id AS memberId, p.product_id AS productId, o.product_name AS productName, o.store_id AS storeId, p.total_amount AS totalAmount, p.down_payment_amount AS downPaymentAmount, p.paid_amount AS paidAmount, p.unpaid_amount AS unpaidAmount, p.installment_count AS installmentCount, p.current_period AS currentPeriod, p.status AS status, DATE_FORMAT(p.activated_at, '%Y-%m-%d %H:%i:%s') AS activatedAt, DATE_FORMAT(p.created_at, '%Y-%m-%d %H:%i:%s') AS createdAt, (select nickname from user_info where userId = p.member_id) AS memberName, (select phone from user_info where userId = p.member_id) AS memberMobile FROM pt_order_installment_plan p LEFT JOIN pt_private_order o ON o.id = p.order_id
ORDER BY p.id DESC
LIMIT #{offset}, #{limit}
